package se.medbo.examplatform.content;
import static org.assertj.core.api.Assertions.assertThat;
import org.flywaydb.core.Flyway;import org.flywaydb.core.api.MigrationVersion;import org.junit.jupiter.api.Test;import org.springframework.jdbc.datasource.DriverManagerDataSource;import org.springframework.jdbc.core.simple.JdbcClient;import org.testcontainers.containers.PostgreSQLContainer;import org.testcontainers.junit.jupiter.Container;import org.testcontainers.junit.jupiter.Testcontainers;
@Testcontainers class ContentMigrationUpgradeTest{
 @Container static final PostgreSQLContainer<?> DB=new PostgreSQLContainer<>("postgres:16-alpine");
 @Test void upgradesPhaseOneFoundation(){Flyway.configure().dataSource(DB.getJdbcUrl(),DB.getUsername(),DB.getPassword()).target(MigrationVersion.fromVersion("1")).load().migrate();Flyway.configure().dataSource(DB.getJdbcUrl(),DB.getUsername(),DB.getPassword()).load().migrate();var jdbc=JdbcClient.create(new DriverManagerDataSource(DB.getJdbcUrl(),DB.getUsername(),DB.getPassword()));assertThat(jdbc.sql("select version from flyway_schema_history where success order by installed_rank").query(String.class).list()).containsExactly("1","2","3","4","5");assertThat(jdbc.sql("select to_regclass('public.exam') is not null and to_regclass('public.source_reference') is not null and to_regclass('public.knowledge_fact_version') is not null and to_regclass('public.question_version') is not null and to_regclass('public.review_record') is not null").query(Boolean.class).single()).isTrue();}
}
